mapper.select:
select u.uid,u.allow_login_ip,u.bot_list,u.google_secret,u.google_secret_flag,u.show_google,u.identity,u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader from sys_user u left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_id = #{sysUser.userId}
AND u.user_name like concat('%', #{sysUser.userName}, '%')
AND u.status = #{sysUser.status}
AND u.phonenumber like concat('%', #{sysUser.phonenumber}, '%')
AND date_format(u.create_time,'%Y%m%d') >= date_format(#{sysUser.params.beginTime},'%Y%m%d')
AND date_format(u.create_time,'%Y%m%d') <= date_format(#{sysUser.params.endTime},'%Y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE find_in_set(#{sysUser.deptId}, ancestors) ))
${sysUser.params.dataScope}

select distinct u.uid,u.allow_login_ip,u.bot_list,u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.user_name like concat('%', #{user.userName}, '%')
AND u.phonenumber like concat('%', #{user.phonenumber}, '%')
${user.params.dataScope}

