update sys_user
dept_id = #{deptId}, user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, google_secret = #{googleSecret}, google_secret_flag = #{googleSecretFlag}, identity = #{identity}, uid = #{uid}, allow_login_ip = #{allowLoginIp}, show_google = #{showGoogle}, update_time = sysdate()
where user_id = #{userId}
